---------------------
---- KEYBINDINGS ----
---------------------

local mainMod = "SUPER" -- Sets "Windows" key as main modifier

-- --- APLICATIVOS E LAUNCHER ---
hl.bind(mainMod .. " + Return",    hl.dsp.exec_cmd(terminal))
hl.bind("CTRL + ALT + T",          hl.dsp.exec_cmd(terminal))
hl.bind("CTRL + space",            hl.dsp.exec_cmd("noctalia msg panel-toggle launcher"))
hl.bind(mainMod .. " + B",         hl.dsp.exec_cmd("zen-browser"))
hl.bind(mainMod .. " + ALT + L",   hl.dsp.exec_cmd("noctalia msg session lock"))
hl.bind(mainMod .. " + SHIFT + Q", hl.dsp.exec_cmd("noctalia msg panel-toggle session"))
hl.bind("CTRL + ALT + C",          hl.dsp.exec_cmd("noctalia msg settings-toggle"))
hl.bind(mainMod .. " + E",         hl.dsp.exec_cmd(fileManager))
hl.bind(mainMod .. " + Q",         hl.dsp.window.close())

-- --- CONTROLES DE MÍDIA (Noctalia IPC) ---
hl.bind("XF86AudioRaiseVolume",  hl.dsp.exec_cmd("noctalia msg volume-up"), { locked = true, repeating = true })
hl.bind("XF86AudioLowerVolume",  hl.dsp.exec_cmd("noctalia msg volume-down"), { locked = true, repeating = true })
hl.bind("XF86AudioMute",         hl.dsp.exec_cmd("noctalia msg volume-mute"), { locked = true, repeating = true })
hl.bind("XF86AudioMicMute",      hl.dsp.exec_cmd("noctalia msg mic-mute"), { locked = true, repeating = true })
hl.bind("XF86AudioNext",         hl.dsp.exec_cmd("noctalia msg media next"), { locked = true })
hl.bind("XF86AudioPrev",         hl.dsp.exec_cmd("noctalia msg media previous"), { locked = true })
hl.bind("XF86AudioPlay",         hl.dsp.exec_cmd("noctalia msg media toggle"), { locked = true })
hl.bind("XF86AudioPause",        hl.dsp.exec_cmd("noctalia msg media toggle"), { locked = true })

-- --- BRILHO DA TELA (Noctalia IPC) ---
hl.bind("XF86MonBrightnessUp",   hl.dsp.exec_cmd("noctalia msg brightness-up"), { locked = true, repeating = true })
hl.bind("XF86MonBrightnessDown", hl.dsp.exec_cmd("noctalia msg brightness-down"), { locked = true, repeating = true })

-- --- NAVEGAÇÃO DE FOCO (Setas / Vim / WASD) ---
local focus_directions = {
    l = {"left", "H", "A"},
    r = {"right", "L", "D"},
    u = {"up", "K", "W"},
    d = {"down", "J", "S"}
}
for dir, keys in pairs(focus_directions) do
    for _, key in ipairs(keys) do
        hl.bind(mainMod .. " + " .. key, hl.dsp.layout("focus " .. dir))
    end
end

-- --- MOVIMENTAÇÃO DE JANELAS (SUPER + CTRL + Setas / Vim / WASD) ---
local move_directions = {
    left =  {"left", "H", "A"},
    right = {"right", "L", "D"},
    up =    {"up", "K", "W"},
    down =  {"down", "J", "S"}
}
for dir, keys in pairs(move_directions) do
    for _, key in ipairs(keys) do
        hl.bind(mainMod .. " + CTRL + " .. key, hl.dsp.window.move({ direction = dir }))
    end
end

-- --- ALTERNAÇÃO E MOVIMENTAÇÃO DE WORKSPACES ---
for i = 1, 9 do
    hl.bind(mainMod .. " + " .. i,        hl.dsp.focus({ workspace = i }))
    hl.bind(mainMod .. " + CTRL + " .. i, hl.dsp.window.move({ workspace = i }))
end
hl.bind(mainMod .. " + TAB", hl.dsp.focus({ workspace = "previous" }))

-- --- ROLAGEM DE WORKSPACES COM MOUSE / TOUCHPAD ---
hl.bind(mainMod .. " + CTRL + mouse_down", hl.dsp.window.move({ workspace = "-1" }))
hl.bind(mainMod .. " + CTRL + mouse_up",   hl.dsp.window.move({ workspace = "+1" }))

-- --- ARRASTAR E REDIMENSIONAR JANELAS ---
hl.bind(mainMod .. " + mouse:272", hl.dsp.window.drag(),   { mouse = true })
hl.bind(mainMod .. " + mouse:273", hl.dsp.window.resize(), { mouse = true })

-- --- CONTROLE DO LAYOUT (Modo Scroll) ---
hl.bind(mainMod .. " + M",     hl.dsp.window.fullscreen({ mode = 1, action = "toggle" }))
hl.bind(mainMod .. " + F",     hl.dsp.window.fullscreen({ action = "toggle" }))
hl.bind(mainMod .. " + T",     hl.dsp.window.float({ action = "toggle" }))
hl.bind(mainMod .. " + C",     hl.dsp.layout("center"))
hl.bind(mainMod .. " + Minus", hl.dsp.layout("colresize -0.1"))
hl.bind(mainMod .. " + Equal", hl.dsp.layout("colresize +0.1"))

-- --- CAPTURAS DE TELA (Screenshots) ---
hl.bind("CTRL + SHIFT + 1", hl.dsp.exec_cmd("grim -g \"$(slurp)\" - | wl-copy"))
hl.bind("CTRL + SHIFT + 2", hl.dsp.exec_cmd("grim - | wl-copy"))
hl.bind("CTRL + SHIFT + 3", hl.dsp.exec_cmd([[grim -g "$(hyprctl activewindow -j | jq -r '"\(.at[0]),\(.at[1]) \(.size[0])x\(.size[1])"')" - | wl-copy]]))
hl.bind("ALT + P",            hl.dsp.exec_cmd("noctalia msg screenshot-region"))
hl.bind("ALT + bracketleft",  hl.dsp.exec_cmd("noctalia msg screenshot-fullscreen"))

-- --- SAÍDA ---
-- 'exit' é o dispatcher correto do hyprctl (o antigo "hyprctl dispatch
-- 'hl.dsp.exit()'" passava código Lua como dispatcher e não fazia nada).
hl.bind("CTRL + ALT + Delete", hl.dsp.exec_cmd("hyprctl dispatch exit"))


