-- See https://wiki.hypr.land/Configuring/Basics/Window-Rules/
-- and https://wiki.hypr.land/Configuring/Basics/Workspace-Rules/

-- Example window rules that are useful

local suppressMaximizeRule = hl.window_rule({
    -- Ignore maximize requests from all apps. You'll probably like this.
    name  = "suppress-maximize-events",
    match = { class = ".*" },

    suppress_event = "maximize",
})
-- suppressMaximizeRule:set_enabled(false)

hl.window_rule({
    -- Fix some dragging issues with XWayland
    name  = "fix-xwayland-drags",
    match = {
        class      = "^$",
        title      = "^$",
        xwayland   = true,
        float      = true,
        fullscreen = false,
        pin        = false,
    },

    no_focus = true,
})

-- Layer rules also return a handle.
-- local overlayLayerRule = hl.layer_rule({
--     name  = "no-anim-overlay",
--     match = { namespace = "^my-overlay$" },
--     no_anim = true,
-- })
-- overlayLayerRule:set_enabled(false)

-- Hyprland-run windowrule
hl.window_rule({
    name  = "move-hyprland-run",
    match = { class = "hyprland-run" },

    move  = "20 monitor_h-120",
    float = true,
})

-- Regras para janelas flutuantes úteis (calculadora, pré-visualizações, diálogos)
hl.window_rule({
    name  = "float-utilities",
    match = { class = "gnome-calculator|org.gnome.NautilusPreviewer|file-roller|pavucontrol" },
    float = true,
})

hl.window_rule({
    name  = "float-dialogs",
    match = { title = "Open File|Save File|Confirm|Preferences|File Operation Progress" },
    float = true,
})

-- Forçar o Calibre (Preferências) a ser ladrilhado (tiled)
hl.window_rule({
    name  = "tile-calibre-preferences",
    match = { class = "calibre-gui", title = "calibre - Preferências" },
    float = false,
})

-- Definir opacidade para o Ghostty (Terminal)
hl.window_rule({
    name  = "ghostty-opacity",
    match = { class = "com.mitchellh.ghostty" },
    opacity = "0.9 0.8",
})

-- Efeito Blur desativado para o Noctalia Shell perante solicitação do usuário
